import { LangGraphAgentScreen } from "@/components/langgraph-agent/langgraph-agent-screen";

export const dynamic = "force-dynamic";

export default function LangGraphAgentPage() {
  return <LangGraphAgentScreen />;
}

import { handleLangGraphAgentRequest } from "@/lib/langgraph-agent/server/runtime";

// This registry item installs the Next.js frontend and proxy route only.
// Run the Python LangGraph backend separately from:
// https://github.com/SawanaLabs/agent-demos/tree/main/apps/langgraph-agent-api
//
// Local-first path: run that backend on http://localhost:2024, then set
// LANGGRAPH_AGENT_API_URL=http://localhost:2024,
// LANGGRAPH_AGENT_ASSISTANT_ID=agent, and LANGGRAPH_AGENT_API_KEY to the same
// shared service key accepted by the backend.
//
// Vercel path: deploy apps/langgraph-agent-api as a FastAPI project using its
// app.py and vercel.json, then point LANGGRAPH_AGENT_API_URL at that deployment.
//
// Official refs:
// - https://docs.langchain.com/langgraph-platform/local-server
// - https://docs.langchain.com/langgraph-platform/cli
// - https://docs.langchain.com/oss/python/langgraph/streaming
// - https://vercel.com/docs/frameworks/backend/fastapi

export const runtime = "nodejs";

export async function POST(request: Request) {
  return handleLangGraphAgentRequest(request);
}

import { TooltipProvider } from "@/components/ui/tooltip";
import { DemoWorkspaceShell } from "@/components/demo-workspace-shell";

import { getLangGraphAgentRuntimeState } from "@/lib/langgraph-agent/server/runtime";
import { LangGraphAgentWorkspace } from "@/components/langgraph-agent/langgraph-agent-workspace";

export function LangGraphAgentScreen() {
  const runtimeState = getLangGraphAgentRuntimeState();

  return (
    <TooltipProvider>
      <DemoWorkspaceShell
        badges={[
          runtimeState.statusLabel,
          runtimeState.modelName,
          runtimeState.assistantId ?? "assistant id missing",
        ]}
        breadcrumbClassName="font-heading text-xs tracking-[0.16em]"
        breadcrumbTitle="LangGraph Agent"
        headerFrame="card"
        summary="This demo validates the copyable frontend slice for teams that already run Python LangGraph agents and want a full-stack product surface."
        title="Official LangGraph thread streaming in a Next.js AI Elements workspace"
      >
        <LangGraphAgentWorkspace
          assistantId={runtimeState.assistantId}
          isChatAvailable={runtimeState.isChatAvailable}
          nodeVersion={runtimeState.nodeVersion}
          remoteUrl={runtimeState.remoteUrl}
          setupMessage={runtimeState.setupMessage}
        />
      </DemoWorkspaceShell>
    </TooltipProvider>
  );
}

"use client";

import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import { Shimmer } from "@/components/ai-elements/shimmer";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import {
  CircleCheckIcon,
  CircleDotDashedIcon,
  GitBranchIcon,
  PlusIcon,
  RefreshCwIcon,
  SquareIcon,
} from "lucide-react";

import {
  ConversationErrorMessage,
  useConversationErrorRetry,
} from "@/components/demo-chat/conversation-error-message";
import type { LangGraphProgressData } from "@/lib/langgraph-agent/server/stream-normalizer";
import { getLangGraphThinkingText } from "./langgraph-agent-message-parts";
import {
  type LangGraphAgentMessage,
  useLangGraphAgent,
} from "./use-langgraph-agent";

const langGraphAgentSamplePrompts = [
  "Plan a safe LangGraph handoff from product research to implementation.",
  "Explain how this thread streams LangGraph node updates into AI SDK UI messages.",
  "Validate the minimum environment setup for running this LangGraph demo locally.",
] as const;

function getTextContent(message: LangGraphAgentMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

function getGraphNodeSummary(events: LangGraphProgressData[]) {
  const latestByNode = new Map<string, LangGraphProgressData>();

  for (const event of events) {
    latestByNode.set(event.node, event);
  }

  return Array.from(latestByNode.values());
}

function formatStateSummary(state: unknown) {
  if (typeof state === "string") {
    return state;
  }

  if (typeof state === "object" && state !== null) {
    return JSON.stringify(state);
  }

  return "Stream event received";
}

function LangGraphAssistantTrace({
  events,
  isLastMessage,
  isStreaming,
  message,
}: {
  events: LangGraphProgressData[];
  isLastMessage: boolean;
  isStreaming: boolean;
  message: LangGraphAgentMessage;
}) {
  const text = getTextContent(message);
  const thinkingText = isLastMessage ? getLangGraphThinkingText(events) : "";
  const showThinking =
    thinkingText.length > 0 || (isLastMessage && isStreaming && !text);

  return (
    <>
      {showThinking ? (
        <Reasoning
          className="w-full"
          defaultOpen={isLastMessage && isStreaming}
          isStreaming={isLastMessage && isStreaming}
        >
          <ReasoningTrigger
            getThinkingMessage={(streaming: boolean, duration?: number) => {
              if (streaming || duration === 0) {
                return (
                  <Shimmer duration={1}>Thinking through LangGraph...</Shimmer>
                );
              }

              if (duration === undefined) {
                return <p>LangGraph thinking</p>;
              }

              return <p>LangGraph thought for {duration} seconds</p>;
            }}
          />
          <ReasoningContent>
            {thinkingText || "- Start run: Waiting for LangGraph node updates."}
          </ReasoningContent>
        </Reasoning>
      ) : null}

      {text ? (
        <MessageResponse>{text}</MessageResponse>
      ) : (
        <Shimmer className="text-sm">Waiting for LangGraph output.</Shimmer>
      )}
    </>
  );
}

function GraphProgressPanel({
  events,
  threadId,
}: {
  events: LangGraphProgressData[];
  threadId: string | null;
}) {
  const nodeSummary = getGraphNodeSummary(events);
  const threadLabel = threadId ?? "Preparing thread...";

  return (
    <div className="space-y-4">
      <div>
        <p className="font-heading text-muted-foreground text-xs uppercase tracking-[0.16em]">
          LangGraph thread
        </p>
        <p className="mt-1 break-all font-mono text-sm">{threadLabel}</p>
      </div>

      <div>
        <p className="font-heading text-muted-foreground text-xs uppercase tracking-[0.16em]">
          Graph progress
        </p>
        <div className="mt-2 space-y-2">
          {nodeSummary.length > 0 ? (
            nodeSummary.map((event) => {
              const isStreaming = event.status === "streaming";

              return (
                <div
                  className="rounded-md border bg-muted/20 px-3 py-2"
                  key={`${event.kind}-${event.node}`}
                >
                  <div className="flex items-center justify-between gap-3">
                    <div className="flex min-w-0 items-center gap-2">
                      {isStreaming ? (
                        <CircleDotDashedIcon className="size-4 shrink-0 text-emerald-600" />
                      ) : (
                        <CircleCheckIcon className="size-4 shrink-0 text-emerald-600" />
                      )}
                      <span className="truncate font-medium text-sm">
                        {event.node}
                      </span>
                    </div>
                    <Badge className="shrink-0" variant="outline">
                      {event.source}
                    </Badge>
                  </div>
                  {event.kind === "node-update" ? (
                    <p className="mt-2 line-clamp-2 break-words text-muted-foreground text-xs">
                      {formatStateSummary(event.state)}
                    </p>
                  ) : (
                    <p className="mt-2 text-muted-foreground text-xs">
                      Streaming tokens from run {event.runId ?? "unknown"}
                    </p>
                  )}
                </div>
              );
            })
          ) : (
            <p className="text-muted-foreground text-sm">
              Submit a message to watch LangGraph updates and streamed answer
              tokens land as AI SDK data parts.
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

export interface LangGraphAgentWorkspaceProps {
  assistantId: string | null;
  isChatAvailable: boolean;
  nodeVersion: string;
  remoteUrl: string | null;
  setupMessage: string | null;
}

export function LangGraphAgentWorkspace({
  assistantId,
  isChatAvailable,
  nodeVersion,
  remoteUrl,
  setupMessage,
}: LangGraphAgentWorkspaceProps) {
  const {
    clearError,
    error,
    graphEvents,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    startNewThread,
    status,
    stop,
    threadId,
  } = useLangGraphAgent();
  const retryConversationError = useConversationErrorRetry({
    clearError,
    regenerate,
  });
  const canStartChatTurn = isChatAvailable && !isBusy;
  const emptyStateDescription = isChatAvailable
    ? "Ask the remote LangGraph agent to explain, plan, or validate a product-agent integration path."
    : "Set LANGGRAPH_AGENT_API_URL and LANGGRAPH_AGENT_ASSISTANT_ID before sending a chat turn.";
  const emptyStateTitle = isChatAvailable
    ? "LangGraph thread is ready"
    : "LangGraph setup is required";

  function sendChatMessage(text: string) {
    if (!canStartChatTurn) {
      return;
    }

    sendMessage({ text });
  }

  function regenerateChatTurn() {
    if (!canStartChatTurn) {
      return;
    }

    regenerate();
  }

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_20rem]">
      <section className="flex min-h-[70svh] flex-col overflow-hidden border border-foreground/10 bg-background text-base text-foreground leading-normal lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <>
            <div className="px-4 py-3 text-muted-foreground text-xs/relaxed">
              {setupMessage}
            </div>
            <Separator />
          </>
        )}

        <Conversation>
          <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
            {hasMessages || error ? (
              <>
                {messages.map((message, index) => {
                  const text = getTextContent(message);
                  let messageBody = (
                    <p className="text-muted-foreground text-sm">
                      Waiting for LangGraph output.
                    </p>
                  );

                  if (message.role === "assistant") {
                    messageBody = (
                      <LangGraphAssistantTrace
                        events={graphEvents}
                        isLastMessage={index === messages.length - 1}
                        isStreaming={isBusy}
                        message={message}
                      />
                    );
                  } else if (text) {
                    messageBody = <MessageResponse>{text}</MessageResponse>;
                  }

                  return (
                    <Message from={message.role} key={message.id}>
                      <MessageContent
                        className={cn(
                          "space-y-4",
                          message.role === "assistant"
                            ? "max-w-3xl"
                            : "max-w-2xl"
                        )}
                      >
                        {messageBody}
                      </MessageContent>
                    </Message>
                  );
                })}
                {error ? (
                  <ConversationErrorMessage
                    error={error}
                    isRetryDisabled={isBusy || !isChatAvailable}
                    onRetry={retryConversationError}
                  />
                ) : null}
              </>
            ) : (
              <ConversationEmptyState
                description={emptyStateDescription}
                icon={<GitBranchIcon className="size-5" />}
                title={emptyStateTitle}
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <Separator />
        <div className="px-4 py-4">
          <div className="mx-auto w-full max-w-3xl">
            <PromptInput onSubmit={({ text }) => sendChatMessage(text)}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!canStartChatTurn}
                  placeholder="Ask the LangGraph agent to reason through an integration or implementation question."
                />
              </PromptInputBody>
              <Separator className="mt-3" />
              <PromptInputFooter className="flex items-center justify-between gap-3 px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">LangGraph</Badge>
                  <Badge variant="outline">AI SDK stream</Badge>
                  <Badge variant="outline">thread scoped</Badge>
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    disabled={isBusy}
                    onClick={startNewThread}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <PlusIcon className="size-3.5" />
                    New thread
                  </Button>
                  {isBusy ? (
                    <Button
                      onClick={stop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <SquareIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      disabled={!canStartChatTurn}
                      onClick={regenerateChatTurn}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <RefreshCwIcon className="size-3.5" />
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!canStartChatTurn}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {langGraphAgentSamplePrompts.map((prompt) => (
                  <Button
                    disabled={!canStartChatTurn}
                    key={prompt}
                    onClick={() => sendChatMessage(prompt)}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <GitBranchIcon className="size-3.5" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <aside className="min-h-0 overflow-y-auto border border-foreground/10 bg-background p-4 text-base text-foreground leading-normal">
        <div className="space-y-5">
          <div className="space-y-4">
            <div>
              <p className="font-heading text-muted-foreground text-xs uppercase tracking-[0.16em]">
                Runtime
              </p>
              <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
            </div>
            <div>
              <p className="font-heading text-muted-foreground text-xs uppercase tracking-[0.16em]">
                Remote API
              </p>
              <p className="mt-1 break-all text-muted-foreground text-sm">
                {remoteUrl ?? "Missing LANGGRAPH_AGENT_API_URL"}
              </p>
            </div>
            <div>
              <p className="font-heading text-muted-foreground text-xs uppercase tracking-[0.16em]">
                Assistant
              </p>
              <p className="mt-1 text-muted-foreground text-sm">
                {assistantId ?? "Missing LANGGRAPH_AGENT_ASSISTANT_ID"}
              </p>
            </div>
          </div>

          <Separator />

          <GraphProgressPanel events={graphEvents} threadId={threadId} />
        </div>
      </aside>
    </div>
  );
}

import type { LangGraphProgressData } from "@/lib/langgraph-agent/server/stream-normalizer";

const nodeLabels: Record<string, string> = {
  answer: "Stream answer",
  plan: "Plan response",
  route: "Route request",
  synthesize: "Prepare final context",
  tool: "Inspect frontend contract",
};

const maxSummaryLength = 220;

function truncateSummary(value: string) {
  const normalized = value.replace(/\s+/g, " ").trim();

  if (normalized.length <= maxSummaryLength) {
    return normalized;
  }

  return `${normalized.slice(0, maxSummaryLength - 1)}...`;
}

function readStringField(state: unknown, field: string) {
  if (typeof state !== "object" || state === null || Array.isArray(state)) {
    return null;
  }

  const value = (state as Record<string, unknown>)[field];

  return typeof value === "string" && value.trim().length > 0 ? value : null;
}

function readFirstObservation(state: unknown) {
  if (typeof state !== "object" || state === null || Array.isArray(state)) {
    return null;
  }

  const observations = (state as Record<string, unknown>).observations;

  if (!Array.isArray(observations)) {
    return null;
  }

  const firstObservation = observations.find(
    (observation): observation is string =>
      typeof observation === "string" && observation.trim().length > 0
  );

  return firstObservation ?? null;
}

function formatNodeUpdateSummary(
  event: Extract<LangGraphProgressData, { kind: "node-update" }>
) {
  if (event.node === "route") {
    return readStringField(event.state, "route") ?? "Route selected.";
  }

  if (event.node === "tool") {
    return (
      readFirstObservation(event.state) ?? "No frontend contract lookup needed."
    );
  }

  if (event.node === "answer") {
    return "Final answer completed.";
  }

  if (event.node === "plan" || event.node === "synthesize") {
    return readStringField(event.state, "plan") ?? "Prepared run context.";
  }

  if (typeof event.state === "string" && event.state.trim().length > 0) {
    return event.state;
  }

  return "Node completed.";
}

function getLatestProgressByNode(events: LangGraphProgressData[]) {
  const latestByNode = new Map<string, LangGraphProgressData>();

  for (const event of events) {
    latestByNode.set(event.node, event);
  }

  return Array.from(latestByNode.values());
}

export function getLangGraphThinkingText(events: LangGraphProgressData[]) {
  return getLatestProgressByNode(events)
    .map((event) => {
      const label = nodeLabels[event.node] ?? event.node;
      const summary =
        event.kind === "node-token"
          ? "Streaming answer tokens."
          : formatNodeUpdateSummary(event);

      return `- ${label}: ${truncateSummary(summary)}`;
    })
    .join("\n");
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { DefaultChatTransport, type UIMessage } from "ai";
import { useCallback, useEffect, useRef, useState } from "react";

import type {
  LangGraphAgentDataParts,
  LangGraphProgressData,
} from "@/lib/langgraph-agent/server/stream-normalizer";

export type LangGraphAgentMessage = UIMessage<unknown, LangGraphAgentDataParts>;

export function createLangGraphThreadId() {
  return crypto.randomUUID();
}

function isGraphProgressDataPart(dataPart: unknown): dataPart is {
  data: LangGraphProgressData;
  type: "data-graph-progress";
} {
  return (
    typeof dataPart === "object" &&
    dataPart !== null &&
    (dataPart as { type?: unknown }).type === "data-graph-progress"
  );
}

export function useLangGraphAgent() {
  const threadIdRef = useRef<string | null>(null);
  const [threadId, setThreadId] = useState<string | null>(null);
  const ensureThreadId = useCallback(() => {
    if (threadIdRef.current) {
      return threadIdRef.current;
    }

    const nextThreadId = createLangGraphThreadId();
    threadIdRef.current = nextThreadId;
    setThreadId(nextThreadId);

    return nextThreadId;
  }, []);
  const [graphEvents, setGraphEvents] = useState<LangGraphProgressData[]>([]);
  /* eslint-disable react-hooks/refs -- Chat transport callbacks run after render and need the current thread id. */
  const [chat] = useState(
    () =>
      new Chat<LangGraphAgentMessage>({
        onData(dataPart) {
          if (isGraphProgressDataPart(dataPart)) {
            setGraphEvents((current) => [...current, dataPart.data]);
          }
        },
        transport: new DefaultChatTransport<LangGraphAgentMessage>({
          api: "/api/demos/langgraph-agent",
          prepareSendMessagesRequest({ messages }) {
            return {
              body: {
                messages,
                threadId: ensureThreadId(),
              },
            };
          },
        }),
      })
  );
  /* eslint-enable react-hooks/refs */
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  useEffect(() => {
    ensureThreadId();
  }, [ensureThreadId]);

  return {
    ...controller,
    graphEvents,
    hasMessages,
    isBusy,
    startNewThread() {
      const nextThreadId = createLangGraphThreadId();
      threadIdRef.current = nextThreadId;
      setThreadId(nextThreadId);
      setGraphEvents([]);
      controller.clearError();
      controller.setMessages([]);
    },
    threadId,
  };
}

"use client";

import {
  Message,
  MessageContent,
} from "@/components/ai-elements/message";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { RefreshCcwIcon } from "lucide-react";
import { useCallback } from "react";

interface ConversationErrorMessageProps {
  className?: string;
  error: Error | string;
  isRetryDisabled?: boolean;
  onRetry?: () => Promise<void> | void;
  retryLabel?: string;
  title?: string;
}

interface UseConversationErrorRetryInput {
  clearError: () => void;
  regenerate: () => Promise<void>;
}

export function useConversationErrorRetry({
  clearError,
  regenerate,
}: UseConversationErrorRetryInput) {
  return useCallback(async () => {
    clearError();
    await regenerate();
  }, [clearError, regenerate]);
}

export function ConversationErrorMessage({
  className,
  error,
  isRetryDisabled = false,
  retryLabel = "Retry",
  onRetry,
  title = "Assistant response failed",
}: ConversationErrorMessageProps) {
  const errorMessage = typeof error === "string" ? error : error.message;

  return (
    <Message from="assistant">
      <MessageContent
        className={cn(
          "max-w-3xl border border-destructive/25 bg-destructive/5 px-4 py-3 text-destructive",
          className
        )}
      >
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0">
            <p className="font-medium text-sm">{title}</p>
            <p className="mt-1 break-words text-xs/relaxed opacity-90">
              {errorMessage}
            </p>
          </div>
          {onRetry ? (
            <Button
              className="self-start"
              disabled={isRetryDisabled}
              onClick={() => {
                void onRetry();
              }}
              size="sm"
              type="button"
              variant="destructive"
            >
              <RefreshCcwIcon className="size-3.5" />
              {retryLabel}
            </Button>
          ) : null}
        </div>
      </MessageContent>
    </Message>
  );
}

import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { cn } from "@/lib/utils";
import type { ReactNode } from "react";

import { DemoBreadcrumb } from "@/components/demo-breadcrumb";

type DemoWorkspaceHeaderFrame = "header" | "card";

interface DemoWorkspaceShellProps {
  badges?: readonly ReactNode[];
  breadcrumbClassName?: string;
  breadcrumbTitle?: string;
  children: ReactNode;
  contentClassName?: string;
  headerClassName?: string;
  headerFrame?: DemoWorkspaceHeaderFrame;
  maxWidthClassName?: string;
  summary: ReactNode;
  summaryClassName?: string;
  title: string;
  titleClassName?: string;
  workspaceClassName?: string | null;
}

const defaultHeaderClassName =
  "grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end";

const cardHeaderClassName =
  "grid gap-4 bg-background px-4 py-5 text-base text-foreground leading-normal md:grid-cols-[minmax(0,1fr)_auto] md:items-end";

export function DemoWorkspaceShell({
  badges = [],
  breadcrumbClassName,
  breadcrumbTitle,
  children,
  contentClassName,
  headerClassName,
  headerFrame = "header",
  maxWidthClassName = "max-w-7xl",
  summary,
  summaryClassName = "max-w-3xl",
  title,
  titleClassName = "max-w-3xl",
  workspaceClassName = "lg:h-svh",
}: DemoWorkspaceShellProps) {
  const headerContent = (
    <>
      <div className="space-y-2">
        <DemoBreadcrumb
          className={breadcrumbClassName}
          title={breadcrumbTitle ?? title}
        />
        <h1
          className={cn("font-medium text-2xl tracking-tight", titleClassName)}
        >
          {title}
        </h1>
        <p
          className={cn(
            "text-muted-foreground text-sm/relaxed",
            summaryClassName
          )}
        >
          {summary}
        </p>
      </div>

      {badges.length > 0 ? (
        <div className="flex flex-wrap items-center gap-2">
          {badges.map((badge, index) => (
            <Badge key={String(index)} variant="outline">
              {badge}
            </Badge>
          ))}
        </div>
      ) : null}
    </>
  );

  return (
    <main className="min-h-svh bg-background text-foreground">
      <div
        className={cn(
