import type { UIMessage } from "ai";

type FetchLike = typeof fetch;

export interface RemoteLangGraphClientOptions {
  apiKey: string;
  baseUrl: string;
  fetch?: FetchLike;
}

export interface StreamThreadRunOptions {
  assistantId: string;
  messages: UIMessage[];
  streamMode?: Array<"updates" | "messages-tuple">;
  threadId: string;
}

interface LangGraphMessage {
  content: string;
  role: "ai" | "human" | "system";
}

const defaultStreamMode: Array<"updates" | "messages-tuple"> = [
  "updates",
  "messages-tuple",
];
const trailingSlashPattern = /\/+$/;

function normalizeBaseUrl(baseUrl: string) {
  const trimmedBaseUrl = baseUrl.trim().replace(trailingSlashPattern, "");

  if (!trimmedBaseUrl) {
    throw new Error("LANGGRAPH_AGENT_API_URL is required.");
  }

  return trimmedBaseUrl;
}

function requireNonEmpty(value: string, name: string) {
  if (!value.trim()) {
    throw new Error(`${name} is required.`);
  }
}

function toLangGraphRole(role: UIMessage["role"]): LangGraphMessage["role"] {
  if (role === "user") {
    return "human";
  }

  if (role === "assistant") {
    return "ai";
  }

  if (role === "system") {
    return "system";
  }

  throw new Error(`Unsupported UI message role for LangGraph: ${role}`);
}

function readTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("");
}

function toLangGraphMessages(messages: UIMessage[]): LangGraphMessage[] {
  return messages.map((message) => {
    const content = readTextContent(message);

    if (!content.trim()) {
      throw new Error(`UI message ${message.id} has no text content.`);
    }

    return {
      content,
      role: toLangGraphRole(message.role),
    };
  });
}

export function createRemoteLangGraphClient({
  apiKey,
  baseUrl,
  fetch: fetchImpl = fetch,
}: RemoteLangGraphClientOptions) {
  const normalizedBaseUrl = normalizeBaseUrl(baseUrl);
  const createJsonHeaders = () => ({
    "content-type": "application/json",
    "x-api-key": apiKey,
  });

  return {
    async streamThreadRun({
      assistantId,
      messages,
      streamMode = defaultStreamMode,
      threadId,
    }: StreamThreadRunOptions) {
      requireNonEmpty(assistantId, "LANGGRAPH_AGENT_ASSISTANT_ID");
      requireNonEmpty(threadId, "threadId");

      const threadResponse = await fetchImpl(`${normalizedBaseUrl}/threads`, {
        body: JSON.stringify({
          if_exists: "do_nothing",
          thread_id: threadId,
        }),
        headers: createJsonHeaders(),
        method: "POST",
      });

      if (!threadResponse.ok) {
        const responseText = await threadResponse.text();
        throw new Error(
          `LangGraph thread creation failed with ${threadResponse.status}: ${responseText}`
        );
      }

      const response = await fetchImpl(
        `${normalizedBaseUrl}/threads/${encodeURIComponent(threadId)}/runs/stream`,
        {
          body: JSON.stringify({
            assistant_id: assistantId,
            input: {
              messages: toLangGraphMessages(messages),
            },
            stream_mode: streamMode,
          }),
          headers: createJsonHeaders(),
          method: "POST",
        }
      );

      if (!response.ok) {
        const responseText = await response.text();
        throw new Error(
          `LangGraph thread run failed with ${response.status}: ${responseText}`
        );
      }

      return response;
    },
  };
}

import {
  createUIMessageStream,
  createUIMessageStreamResponse,
  type UIMessage,
  validateUIMessages,
} from "ai";

import {
  DEFAULT_LANGGRAPH_AGENT_MODEL,
  getLangGraphAgentConfig,
  getLangGraphAgentEnv,
  getLangGraphAgentSetupState,
  type LangGraphAgentEnv,
} from "./env";
import { createRemoteLangGraphClient } from "./remote-langgraph-client";
import { parseLangGraphSseStream } from "./sse-parser";
import { createLangGraphStreamNormalizer } from "./stream-normalizer";

interface LangGraphAgentRequestBody {
  messages?: UIMessage[];
  threadId?: string;
}

export interface LangGraphAgentRuntimeState {
  assistantId: string | null;
  isChatAvailable: boolean;
  modelName: string;
  nodeVersion: string;
  remoteUrl: string | null;
  setupMessage: string | null;
  statusLabel: "Ready" | "Setup required";
}

export interface LangGraphAgentStreamInput {
  messages: UIMessage[];
  threadId: string;
}

interface LangGraphAgentClient {
  streamThreadRun: (
    input: Parameters<
      ReturnType<typeof createRemoteLangGraphClient>["streamThreadRun"]
    >[0]
  ) => Promise<Response>;
}

interface LangGraphAgentStreamDependencies {
  client?: LangGraphAgentClient;
}

interface LangGraphAgentRequestDependencies {
  streamLangGraphAgent: (
    input: LangGraphAgentStreamInput,
    env: LangGraphAgentEnv
  ) => Promise<Response> | Response;
}

const invalidRequestError =
  'Expected a JSON body with "messages" array and "threadId" string.';
const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';

function readThreadId(body: LangGraphAgentRequestBody) {
  if (typeof body.threadId !== "string" || !body.threadId.trim()) {
    throw new Error(invalidRequestError);
  }

  return body.threadId;
}

async function readLangGraphAgentInput(
  body: unknown
): Promise<LangGraphAgentStreamInput> {
  const requestBody = (body ?? {}) as LangGraphAgentRequestBody;

  if (!Array.isArray(requestBody.messages)) {
    throw new Error(invalidRequestError);
  }

  try {
    return {
      messages: await validateUIMessages({
        messages: requestBody.messages,
      }),
      threadId: readThreadId(requestBody),
    };
  } catch (error) {
    if (error instanceof Error && error.message === invalidRequestError) {
      throw error;
    }

    throw new Error(invalidUiMessagesError);
  }
}

export function getLangGraphAgentRuntimeState(
  env: LangGraphAgentEnv = getLangGraphAgentEnv()
): LangGraphAgentRuntimeState {
  const setup = getLangGraphAgentSetupState(env);

  return {
    assistantId: setup.config.assistantId ?? null,
    isChatAvailable: setup.isReady,
    modelName: setup.config.modelName ?? DEFAULT_LANGGRAPH_AGENT_MODEL,
    nodeVersion: setup.nodeVersion,
    remoteUrl: setup.config.baseUrl ?? null,
    setupMessage: setup.issues.length > 0 ? setup.issues.join(" ") : null,
    statusLabel: setup.isReady ? "Ready" : "Setup required",
  };
}

export async function streamLangGraphAgent(
  input: LangGraphAgentStreamInput,
  env: LangGraphAgentEnv = getLangGraphAgentEnv(),
  dependencies: LangGraphAgentStreamDependencies = {}
) {
  const config = getLangGraphAgentConfig(env);
  const client =
    dependencies.client ??
    createRemoteLangGraphClient({
      apiKey: config.apiKey,
      baseUrl: config.baseUrl,
    });
  const remoteResponse = await client.streamThreadRun({
    assistantId: config.assistantId,
    messages: input.messages,
    threadId: input.threadId,
  });

  if (!remoteResponse.body) {
    throw new Error("LangGraph stream response did not include a body.");
  }

  const normalizer = createLangGraphStreamNormalizer();

  return createUIMessageStreamResponse({
    stream: createUIMessageStream({
      async execute({ writer }) {
        for await (const event of parseLangGraphSseStream(
          remoteResponse.body as ReadableStream<Uint8Array>
        )) {
          for (const chunk of normalizer.normalize(event)) {
            writer.write(chunk);
          }
        }

        for (const chunk of normalizer.finish()) {
          writer.write(chunk);
        }
      },
      onError(error) {
        return error instanceof Error
          ? error.message
          : "LangGraph agent stream failed.";
      },
    }),
  });
}

export async function handleLangGraphAgentRequest(
  request: Request,
  env: LangGraphAgentEnv = getLangGraphAgentEnv(),
  dependencies: LangGraphAgentRequestDependencies = {
    streamLangGraphAgent,
  }
) {
  const runtimeState = getLangGraphAgentRuntimeState(env);

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  try {
    const input = await readLangGraphAgentInput(await request.json());

    return dependencies.streamLangGraphAgent(input, env);
  } catch (error) {
    if (
      error instanceof Error &&
      [invalidRequestError, invalidUiMessagesError].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }
}

import type { LangGraphStreamEvent } from "./stream-normalizer";

interface SseFrameFields {
  dataLines: string[];
  event?: string;
}

function readSseLine(line: string, fields: SseFrameFields) {
  if (!line || line.startsWith(":")) {
    return;
  }

  const separatorIndex = line.indexOf(":");
  const field = separatorIndex === -1 ? line : line.slice(0, separatorIndex);
  const rawValue = separatorIndex === -1 ? "" : line.slice(separatorIndex + 1);
  const value = rawValue.startsWith(" ") ? rawValue.slice(1) : rawValue;

  if (field === "event") {
    fields.event = value;
    return;
  }

  if (field === "data") {
    fields.dataLines.push(value);
  }
}

function parseSseFrame(frame: string): LangGraphStreamEvent | null {
  const fields: SseFrameFields = {
    dataLines: [],
  };

  for (const line of frame.split("\n")) {
    readSseLine(line, fields);
  }

  if (!fields.event && fields.dataLines.length === 0) {
    return null;
  }

  const dataText = fields.dataLines.join("\n");

  if (dataText === "[DONE]") {
    return null;
  }

  if (dataText.length === 0) {
    return {
      event: fields.event,
    };
  }

  try {
    return {
      data: JSON.parse(dataText) as unknown,
      event: fields.event,
    };
  } catch (error) {
    throw new Error(
      `Unable to parse LangGraph SSE data as JSON for event "${fields.event ?? "message"}": ${
        error instanceof Error ? error.message : "unknown parse error"
      }`
    );
  }
}

export async function* parseLangGraphSseStream(
  stream: ReadableStream<Uint8Array>
): AsyncGenerator<LangGraphStreamEvent> {
  const decoder = new TextDecoder();
  const reader = stream.getReader();
  let buffer = "";

  try {
    while (true) {
      const { done, value } = await reader.read();

      if (done) {
        break;
      }

      buffer += decoder.decode(value, { stream: true }).replace(/\r\n/g, "\n");

      while (buffer.includes("\n\n")) {
        const frameEnd = buffer.indexOf("\n\n");
        const frame = buffer.slice(0, frameEnd);
        buffer = buffer.slice(frameEnd + 2);
        const event = parseSseFrame(frame);

        if (event) {
          yield event;
        }
      }
    }

    buffer += decoder.decode().replace(/\r\n/g, "\n");

    if (buffer.trim()) {
      const event = parseSseFrame(buffer);

      if (event) {
        yield event;
      }
    }
  } finally {
    reader.releaseLock();
  }
}

import type { UIMessageChunk } from "ai";

export type LangGraphProgressData =
  | {
      kind: "node-token";
      node: string;
      runId?: string;
      source: "messages" | "messages-tuple";
      status: "streaming";
    }
  | {
      kind: "node-update";
      node: string;
      source: "updates";
      state: unknown;
      status: "completed";
    };

export interface LangGraphAgentDataParts extends Record<string, unknown> {
  "graph-progress": LangGraphProgressData;
}

export type LangGraphAgentMessageChunk = UIMessageChunk<
  unknown,
  LangGraphAgentDataParts
>;

export interface LangGraphStreamNormalizerOptions {
  textPartId?: string;
}

export interface LangGraphStreamEvent {
  data?: unknown;
  event?: string;
  type?: string;
}

interface MessageTupleMetadata {
  langgraph_node?: unknown;
  run_id?: unknown;
}

interface MessageTupleChunk {
  content?: unknown;
}

const defaultTextPartId = "langgraph-answer";

function getStreamEventType(event: LangGraphStreamEvent) {
  return event.event ?? event.type;
}

function readMessageContent(chunk: unknown) {
  if (typeof chunk === "string") {
    return chunk;
  }

  if (typeof chunk !== "object" || chunk === null) {
    return "";
  }

  const { content } = chunk as MessageTupleChunk;

  return typeof content === "string" ? content : "";
}

function readNodeName(metadata: unknown) {
  if (typeof metadata !== "object" || metadata === null) {
    return "unknown";
  }

  const { langgraph_node } = metadata as MessageTupleMetadata;

  return typeof langgraph_node === "string" && langgraph_node.length > 0
    ? langgraph_node
    : "unknown";
}

function readRunId(metadata: unknown) {
  if (typeof metadata !== "object" || metadata === null) {
    return;
  }

  const { run_id } = metadata as MessageTupleMetadata;

  return typeof run_id === "string" && run_id.length > 0 ? run_id : undefined;
}

function normalizeMessageTuple(
  event: LangGraphStreamEvent,
  eventType: "messages" | "messages-tuple",
  textPartId: string,
  hasStartedText: boolean
) {
  if (!Array.isArray(event.data) || event.data.length < 2) {
    throw new Error(`Expected ${eventType} data to be a message tuple.`);
  }

  const [messageChunk, metadata] = event.data;
  const text = readMessageContent(messageChunk);
  const node = readNodeName(metadata);
  const chunks: LangGraphAgentMessageChunk[] = [
    {
      data: {
        kind: "node-token",
        node,
        runId: readRunId(metadata),
        source: eventType,
        status: "streaming",
      },
      id: `node-${node}`,
      transient: true,
      type: "data-graph-progress",
    },
  ];

  if (!text) {
    return {
      chunks,
      hasStartedText,
    };
  }

  if (!hasStartedText) {
    chunks.push({
      id: textPartId,
      type: "text-start",
    });
  }

  chunks.push({
    delta: text,
    id: textPartId,
    type: "text-delta",
  });

  return {
    chunks,
    hasStartedText: true,
  };
}

function normalizeUpdates(event: LangGraphStreamEvent) {
  if (
    typeof event.data !== "object" ||
    event.data === null ||
    Array.isArray(event.data)
  ) {
    throw new Error("Expected updates data to be an object keyed by node.");
  }

  return Object.entries(event.data).map(
    ([node, state]): LangGraphAgentMessageChunk => ({
      data: {
        kind: "node-update",
        node,
        source: "updates",
        state,
        status: "completed",
      },
      id: `node-${node}`,
      transient: false,
      type: "data-graph-progress",
    })
  );
}

export function createLangGraphStreamNormalizer({
  textPartId = defaultTextPartId,
}: LangGraphStreamNormalizerOptions = {}) {
  let hasStartedText = false;

  return {
    finish(): LangGraphAgentMessageChunk[] {
      if (!hasStartedText) {
        return [];
      }

      hasStartedText = false;

      return [
        {
          id: textPartId,
          type: "text-end",
        },
      ];
    },
    normalize(event: LangGraphStreamEvent): LangGraphAgentMessageChunk[] {
      const eventType = getStreamEventType(event);

      if (eventType === "updates") {
        return normalizeUpdates(event);
      }

      if (eventType === "messages" || eventType === "messages-tuple") {
        const result = normalizeMessageTuple(
          event,
          eventType,
          textPartId,
          hasStartedText
        );
        hasStartedText = result.hasStartedText;

        return result.chunks;
      }

      if (
        eventType === "end" ||
        eventType === "metadata" ||
        eventType === "values"
      ) {
        return [];
      }

      throw new Error(`Unsupported LangGraph stream event: ${eventType}`);
    },
  };
}
